import SwiftUI
struct RedeemSheet: View { @EnvironmentObject private var subManager: SubscriptionManager; @Environment(\.modelContext) private var modelContext; @Environment(\.dismiss) private var dismiss; @State private var codeBlocks: [String] = ["", ""]; @FocusState private var focusedBlock: Int?; private let blockLength = 4
    var body: some View { NavigationStack { VStack(spacing: Spacing.lg) { Image(systemName: "gift.fill").font(.system(size: 48)).foregroundStyle(LinearGradient(colors: [.tealLink, .oceanDeep], startPoint: .topLeading, endPoint: .bottomTrailing)).padding(.top, Spacing.xxl); Text("兑换邀请码").font(.cnTitle2).foregroundColor(.textPrimary); Text("输入作者提供的邀请码，
解锁一年 Pro 会员").font(.cnSubhead).foregroundColor(.textSecondary).multilineTextAlignment(.center); HStack(spacing: Spacing.sm) { Text("CNET").font(.cnTitle3).foregroundColor(.textTertiary); Text("-").font(.cnTitle3).foregroundColor(.textTertiary); codeField(index: 0); Text("-").font(.cnTitle3).foregroundColor(.textTertiary); codeField(index: 1) }; if let msg = RedeemCodeManager.shared.redemptionMessage { HStack(spacing: Spacing.xs) { Image(systemName: "exclamationmark.triangle.fill").font(.system(size: 12)); Text(msg).font(.cnCaption1) }.foregroundColor(.coralWarm).padding(.horizontal, Spacing.base).padding(.vertical, Spacing.sm).background(Color.coralWarm.opacity(0.08)).clipShape(RoundedRectangle(cornerRadius: CornerRadius.tag)) }; Button { redeem() } label: { HStack { if RedeemCodeManager.shared.isRedeeming { ProgressView().tint(.white) }; Text(RedeemCodeManager.shared.isRedeeming ? "兑换中…" : "兑换").font(.cnHeadline) }.frame(maxWidth: .infinity).padding(.vertical, 14).background(RoundedRectangle(cornerRadius: CornerRadius.button).fill(codeIsComplete ? AnyShapeStyle(LinearGradient(colors: [.tealLink, .oceanDeep], startPoint: .leading, endPoint: .trailing)) : AnyShapeStyle(Color.textTertiary.opacity(0.3)))).foregroundColor(codeIsComplete ? .white : .textTertiary) }.disabled(!codeIsComplete || RedeemCodeManager.shared.isRedeeming).padding(.horizontal, Spacing.base); Spacer(); Text("每个邀请码仅可使用一次").font(.cnCaption2).foregroundColor(.textTertiary).padding(.bottom, Spacing.lg) }.background(Color.surfaceLight).toolbar { ToolbarItem(placement: .topBarTrailing) { Button { dismiss() } label: { Image(systemName: "xmark.circle.fill").font(.system(size: 24)).foregroundColor(.textTertiary) } } } } }
    private func codeField(index: Int) -> some View { TextField("XXXX", text: $codeBlocks[index]).font(.cnTitle3.monospaced()).foregroundColor(.textPrimary).multilineTextAlignment(.center).textInputAutocapitalization(.characters).autocorrectionDisabled().focused($focusedBlock, equals: index).onChange(of: codeBlocks[index]) { _, newValue in let cleaned = newValue.uppercased().filter { $0.isLetter || $0.isNumber }; codeBlocks[index] = cleaned.count > blockLength ? String(cleaned.prefix(blockLength)) : cleaned; if codeBlocks[index].count == blockLength && index < 1 { focusedBlock = index + 1 } }.frame(width: 80).padding(.vertical, 12).background(RoundedRectangle(cornerRadius: CornerRadius.nestedCard).fill(Color.surfaceCard).overlay(RoundedRectangle(cornerRadius: CornerRadius.nestedCard).stroke(focusedBlock == index ? Color.tealLink : Color.divider, lineWidth: focusedBlock == index ? 1.5 : 0.5))).multilineTextAlignment(.center) }
    private var codeIsComplete: Bool { codeBlocks.allSatisfy { $0.count == blockLength } }; private var fullCode: String { "CNET-\(codeBlocks[0])-\(codeBlocks[1])" }
    private func redeem() { guard codeIsComplete else { return }; Task { let success = await RedeemCodeManager.shared.redeem(fullCode, modelContext: modelContext); if success { try? await Task.sleep(nanoseconds: 800_000_000); dismiss() } } }
}